				"request_id":    "req-1",
				"namespace_key": "production",
				"flag_key":      "flag1",
				"entity_id":     "user1",
				"context": map[string]string{
					"env": "prod",
				},
			},
			{
				"request_id":    "req-2",
				"namespace_key": "production",
				"flag_key":      "flag2",
				"entity_id":     "user2",
				"context": map[string]string{
					"env": "prod",
				},
			},
		},
	}

	bodyBytes, err := json.Marshal(body)
	require.NoError(t, err)

	resp, err := http.Post(
		client.URL+"/evaluate/v1/batch",
		"application/json",
		bytes.NewReader(bodyBytes),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Verify response is successful
	if resp.StatusCode != http.StatusOK {
		bodyContent, _ := io.ReadAll(resp.Body)
		t.Fatalf("expected status 200, got %d: %s", resp.StatusCode, string(bodyContent))
	}

	var result rpcevaluation.BatchEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, "batch-request-1", result.RequestId)
}

// TestFlagNotFoundError tests 404 behavior when flag doesn't exist
func TestFlagNotFoundError(t *testing.T) {
	client := setupEvaluationTestServer(t)
	defer client.Close()

	body := map[string]interface{}{
		"request_id":    "test-not-found",
		"namespace_key": "production",
		"flag_key":      "nonexistent_flag",
		"entity_id":     "user789",
	}

	bodyBytes, err := json.Marshal(body)
	require.NoError(t, err)

	resp, err := http.Post(
		client.URL+"/evaluate/v1/boolean",
		"application/json",
		bytes.NewReader(bodyBytes),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Flag not found should result in error response (500 or appropriate error status)
	assert.True(t, resp.StatusCode >= 400, "expected error status code for non-existent flag")
}

// TestNamespaceScopedEvaluation tests that namespaces are properly scoped
func TestNamespaceScopedEvaluation(t *testing.T) {
	client := setupEvaluationTestServer(t)
	defer client.Close()

	// Test with different namespaces
	for _, namespace := range []string{"production", "staging", "development"} {
		body := map[string]interface{}{
			"request_id":    "test-" + namespace,
			"namespace_key": namespace,
			"flag_key":      "test_flag",
			"entity_id":     "user_ns_test",
			"context": map[string]string{
				"namespace": namespace,
			},
		}

		bodyBytes, err := json.Marshal(body)
		require.NoError(t, err)

		resp, err := http.Post(
			client.URL+"/evaluate/v1/boolean",
			"application/json",
			bytes.NewReader(bodyBytes),
		)
		require.NoError(t, err)
		defer resp.Body.Close()

		// Each request should either succeed or fail consistently
		assert.NotNil(t, resp, "response should not be nil for namespace %s", namespace)
	}
}

// TestInvalidRequestBodyBooleanEvaluation tests 400 behavior with malformed request
func TestInvalidRequestBodyBooleanEvaluation(t *testing.T) {
	client := setupEvaluationTestServer(t)
	defer client.Close()

	// Send invalid JSON
	resp, err := http.Post(
		client.URL+"/evaluate/v1/boolean",
		"application/json",
		bytes.NewReader([]byte("invalid json {")),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Invalid request should return 400 Bad Request
	assert.True(t, resp.StatusCode == http.StatusBadRequest || resp.StatusCode == http.StatusUnprocessableEntity,
		"expected 400 or 422 for invalid JSON, got %d", resp.StatusCode)
}

// TestMissingRequiredFieldsVariantEvaluation tests validation of required fields
func TestMissingRequiredFieldsVariantEvaluation(t *testing.T) {
	client := setupEvaluationTestServer(t)
	defer client.Close()

	// Request missing namespace_key (required field)
	body := map[string]interface{}{
		"request_id": "test-missing-fields",
		"flag_key":   "test_flag",
		"entity_id":  "user123",
	}

	bodyBytes, err := json.Marshal(body)
	require.NoError(t, err)

	resp, err := http.Post(
		client.URL+"/evaluate/v1/variant",
		"application/json",
		bytes.NewReader(bodyBytes),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Missing required fields should result in error (400 or 500)
	assert.True(t, resp.StatusCode >= 400, "expected error status for missing required fields")
}

// TestBatchEvaluationWithMixedResults tests batch evaluation with both success and error responses
func TestBatchEvaluationWithMixedResults(t *testing.T) {
	client := setupEvaluationTestServer(t)
	defer client.Close()

	body := map[string]interface{}{
		"request_id": "batch-mixed",
		"requests": []map[string]interface{}{
			{
				"request_id":    "req-valid",
				"namespace_key": "production",
				"flag_key":      "existing_flag",
				"entity_id":     "user1",
			},
			{
				"request_id":    "req-nonexistent",
				"namespace_key": "production",
				"flag_key":      "nonexistent_flag",
				"entity_id":     "user2",
			},
		},
	}

	bodyBytes, err := json.Marshal(body)
	require.NoError(t, err)

	resp, err := http.Post(
		client.URL+"/evaluate/v1/batch",
		"application/json",
		bytes.NewReader(bodyBytes),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Batch should return 200 with mixed results
	if resp.StatusCode != http.StatusOK {
		bodyContent, _ := io.ReadAll(resp.Body)
		t.Fatalf("expected status 200, got %d: %s", resp.StatusCode, string(bodyContent))
	}

	var result rpcevaluation.BatchEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	// Should have responses for both requests
	assert.NotEmpty(t, result.Responses)
}

// setupEvaluationTestServer creates a test HTTP server with the evaluation API
func setupEvaluationTestServer(t *testing.T) *httptest.Server {
	t.Helper()

	// Create a mock store for testing
	store := &mockEvaluationStore{}

	// Setup gRPC Server
	listener := bufconn.Listen(1024 * 1024)
	grpcServer := grpc.NewServer()
	evaluationServer := evaluation.New(zaptest.NewLogger(t), store)
	evaluationServer.RegisterGRPC(grpcServer)

	go func() {
		if err := grpcServer.Serve(listener); err != nil {
			t.Logf("error serving grpc: %v", err)
		}
	}()
	t.Cleanup(grpcServer.Stop)

	// Setup gRPC Client connection to the test server
	conn, err := grpc.DialContext(
		context.Background(),
		"",
		grpc.WithTransportCredentials(insecure.NewCredentials()),
		grpc.WithContextDialer(func(context.Context, string) (net.Conn, error) {
			return listener.Dial()
		}),
	)
	require.NoError(t, err)
	t.Cleanup(func() { conn.Close() })

	// Setup HTTP Gateway mux
	mux := gateway.NewGatewayServeMux(zaptest.NewLogger(t))
	err = rpcevaluation.RegisterEvaluationServiceHandler(context.Background(), mux, conn)
	require.NoError(t, err)

	// Create HTTP test server with the gateway mux
	httpServer := httptest.NewServer(mux)
	t.Cleanup(httpServer.Close)

	return httpServer
}

// mockEvaluationStore implements the evaluation.Storer interface for testing
type mockEvaluationStore struct{}

func (m *mockEvaluationStore) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	// Return different flags based on the flag key for testing
	switch req.GetKey() {
	case "test_flag", "existing_flag":
		return &flipt.Flag{
			NamespaceKey: req.GetNamespace(),
			Key:          req.GetKey(),
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil
	case "variant_flag":
		return &flipt.Flag{
			NamespaceKey: req.GetNamespace(),
			Key:          req.GetKey(),
			Enabled:      true,
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		}, nil
	case "flag1", "flag2":
		return &flipt.Flag{
			NamespaceKey: req.GetNamespace(),
			Key:          req.GetKey(),
			Enabled:      true,
			Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		}, nil
	default:
		// Flag not found
		return nil, &notFoundError{msg: req.GetKey() + " not found"}
	}
}

func (m *mockEvaluationStore) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	return []*storage.EvaluationRule{}, nil
}

func (m *mockEvaluationStore) GetEvaluationDistributions(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
	return []*storage.EvaluationDistribution{}, nil
}

func (m *mockEvaluationStore) GetEvaluationRollouts(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
	return []*storage.EvaluationRollout{}, nil
}

// notFoundError implements the storage error interface
type notFoundError struct {
	msg string
}

func (e *notFoundError) Error() string {
	return e.msg
}

// Ensure the mock implements the error interface
var _ error = (*notFoundError)(nil)

