package integration

import (
	"bytes"
	"context"
	"encoding/json"
	"io"
	"net"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/gateway"
	"go.flipt.io/flipt/internal/server/evaluation"
	"go.flipt.io/flipt/internal/storage"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/test/bufconn"
)

// TestBooleanFlagEvaluationSuccess tests successful boolean flag evaluation
func TestBooleanFlagEvaluationSuccess(t *testing.T) {
	client := setupEvaluationTestServer(t)
	defer client.Close()

	body := map[string]interface{}{
		"request_id":    "test-request-1",
		"namespace_key": "production",
		"flag_key":      "test_flag",
		"entity_id":     "user123",
		"context": map[string]string{
			"plan": "pro",
		},
	}

	bodyBytes, err := json.Marshal(body)
	require.NoError(t, err)

	resp, err := http.Post(
		client.URL+"/evaluate/v1/boolean",
		"application/json",
		bytes.NewReader(bodyBytes),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Verify the response has correct status code
	if resp.StatusCode != http.StatusOK {
		bodyContent, _ := io.ReadAll(resp.Body)
		t.Fatalf("expected status 200, got %d: %s", resp.StatusCode, string(bodyContent))
	}

	var result rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	assert.Equal(t, "test-request-1", result.RequestId)
	assert.NotEmpty(t, result.Reason)
}

// TestVariantFlagEvaluationSuccess tests successful variant flag evaluation
func TestVariantFlagEvaluationSuccess(t *testing.T) {
	client := setupEvaluationTestServer(t)
	defer client.Close()

	body := map[string]interface{}{
		"request_id":    "test-request-2",
		"namespace_key": "production",
		"flag_key":      "variant_flag",
