// TestBatchEvaluationSuccess tests batch evaluation with multiple flag requests
func TestBatchEvaluationSuccess(t *testing.T) {
	client := setupEvaluationTestServer(t)
	defer client.Close()

	body := map[string]interface{}{
		"request_id": "batch-request-1",
		"requests": []map[string]interface{}{
			{
				"request_id":    "req-1",
				"namespace_key": "production",
				"flag_key":      "flag1",
				"entity_id":     "user1",
				"context": map[string]string{
					"env": "prod",
				},
			},
			{
				"request_id":    "req-2",
				"namespace_key": "production",
				"flag_key":      "flag2",
				"entity_id":     "user2",
				"context": map[string]string{
					"env": "prod",
				},
			},
		},
	}

	bodyBytes, err := json.Marshal(body)
	require.NoError(t, err)

	resp, err := http.Post(
		client.URL+"/evaluate/v1/batch",
